export const allowCreateForContentType = (
  entryId: ContentTypeId,
): RoleProps["policies"][number] => {
  return {
    effect: "allow",
    constraint: {
      and: [
        {
          equals: [
            {
              doc: "sys.type",
            },
            "Entry",
          ],
        },
        {
          equals: [
            {
              doc: "sys.contentType.sys.id",
            },

            entryId,
          ],
        },
      ],
    },
    actions: ["create"],
  };
};

