export const allowEditForTag = (
  tag: LocaleTag,
): RoleProps["policies"][number] => {
  return {
    effect: "allow",
    constraint: {
      and: [
        {
          equals: [
            {
              doc: "sys.type",
            },
            "Entry",
          ],
        },
        {
          paths: [
            {
              doc: "fields.%.%",
            },
          ],
        },
        {
          in: [
            {
              doc: "metadata.tags.sys.id",
            },
            [tag],
          ],
        },
      ],
    },
    actions: ["update"],
  };
};

